#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        static char P[100005];
        static char C[100005];
        scanf("%s", P);
        scanf("%s", C);
        for (int i = 0; i < N; ++i) {
            int p = P[i] - 'A';
            int c = C[i] - 'A';
            int diff = (c - p + 26) % 26;
            int k = (diff * 9) % 26; // 9 is modular inverse of 3 modulo 26
            if (i) printf(" ");
            printf("%d", k);
        }
        printf("\n");
    }
    return 0;
}

