const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let output = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const P = input[idx++];
  const C = input[idx++];
  let line = [];
  for (let i = 0; i < N; ++i) {
    const p = P.charCodeAt(i) - 65;
    const c = C.charCodeAt(i) - 65;
    const diff = (c - p + 26) % 26;
    const k = (diff * 9) % 26; // inverse of 3 modulo 26
    line.push(k.toString());
  }
  output.push(line.join(' '));
}
